export enum BusType {
  STANDARD = 'اقتصادية',
  VIP = 'كبار الشخصيات',
  ROYAL = 'رويال الملكية'
}

export interface Driver {
  id: string;
  name: string;
  rating: number;
  experience: string;
  photo: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  loggedIn: boolean;
}

export interface Ticket {
  id: string;
  userId: string;
  from: string;
  to: string;
  busType: BusType;
  driverId: string;
  date: string;
  arrivalTime: string;
  price: number;
  status: 'upcoming' | 'completed' | 'cancelled';
  rating?: number;
  review?: string;
}

export interface Complaint {
  id: string;
  userId: string;
  subject: string;
  description: string;
  date: string;
  status: 'pending' | 'resolved';
}

export interface BookingState {
  from: string;
  to: string;
  busType: BusType;
  driver: Driver | null;
  date: string;
  arrivalTime: string;
}

