import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const analyzeComplaint = async (subject: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        بصفتك مسؤول خدمة عملاء في شركة "تاج باص" لحجز التذاكر، قم بتحليل الشكوى التالية وقدم رداً احترافياً وودوداً باللغة العربية.
        الموضوع: ${subject}
        الوصف: ${description}

        الرد يجب أن يتضمن:
        1. اعتذاراً لبقاً.
        2. تأكيداً على اهتمام الشركة.
        3. وعداً بالتحقيق في الأمر خلال 24 ساعة.
      `,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "شكراً لتقديم بلاغك، سنقوم بمراجعة الشكوى والرد عليك في أقرب وقت ممكن.";
  }
};

