import React, { useState } from 'react';
import { User } from '../types';

interface AuthFormProps {
  onLogin: (user: User) => void;
}

const AuthForm: React.FC<AuthFormProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Simplified Mock Auth
    onLogin({
      id: Math.random().toString(36).substr(2, 9),
      name: formData.name || 'مستخدم جديد',
      email: formData.email,
      loggedIn: true
    });
  };

  return (
    <div className="max-w-md mx-auto my-12 bg-white rounded-2xl shadow-xl overflow-hidden border border-gray-100">
      <div className="bg-blue-900 py-6 px-8 text-center text-white">
        <h2 className="text-2xl font-bold mb-2">{isLogin ? 'تسجيل الدخول' : 'إنشاء حساب جديد'}</h2>
        <p className="text-blue-200 text-sm">أهلاً بك في تاج باص، رفيقك في السفر</p>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-5">
        {!isLogin && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">الاسم بالكامل</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              value={formData.name}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
            />
          </div>
        )}

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">البريد الإلكتروني</label>
          <input
            type="email"
            required
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={formData.email}
            onChange={(e) => setFormData({...formData, email: e.target.value})}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">كلمة المرور</label>
          <input
            type="password"
            required
            className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={formData.password}
            onChange={(e) => setFormData({...formData, password: e.target.value})}
          />
        </div>

        <button 
          type="submit"
          className="w-full bg-blue-900 hover:bg-blue-800 text-white py-3 rounded-lg font-bold transition-all shadow-lg active:scale-95"
        >
          {isLogin ? 'دخول' : 'إنشاء الحساب'}
        </button>

        <div className="text-center pt-4 border-t border-gray-100">
          <button 
            type="button"
            onClick={() => setIsLogin(!isLogin)}
            className="text-blue-600 font-medium hover:underline text-sm"
          >
            {isLogin ? 'لا تملك حساباً؟ سجل الآن' : 'لديك حساب بالفعل؟ ادخل هنا'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default AuthForm;

import React, { useState } from 'react';
import { CITIES, BUS_PRICES, DRIVERS } from '../constants';
import { BusType, Driver, BookingState, Ticket } from '../types';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [booking, setBooking] = useState<BookingState>({
    from: '',
    to: '',
    busType: BusType.STANDARD,
    driver: null,
    date: '',
    arrivalTime: '12:00'
  });

  const calculatePrice = () => {
    const base = BUS_PRICES[booking.busType];
    const driverBonus = booking.driver ? (booking.driver.rating * 20) : 0;
    return base + driverBonus;
  };

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const handleFinish = () => {
    const ticket: Ticket = {
      id: Math.random().toString(36).substr(2, 9),
      userId: 'current-user',
      ...booking,
      driverId: booking.driver?.id || '',
      price: calculatePrice(),
      status: 'upcoming'
    };
    onComplete(ticket);
  };

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      {/* Progress Stepper */}
      <div className="flex items-center justify-between mb-12 relative px-4">
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-200 -z-10 -translate-y-1/2 mx-10"></div>
        {[1, 2, 3, 4].map((i) => (
          <div 
            key={i}
            className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all border-2
              ${step >= i ? 'bg-blue-900 text-white border-blue-900' : 'bg-white text-gray-400 border-gray-200'}`}
          >
            {i}
          </div>
        ))}
      </div>

      <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100 min-h-[400px]">
        {/* Step 1: Destination & Date */}
        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">حدد وجهتك وموعدك</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">من (نقطة المغادرة)</label>
                <select 
                  className="w-full p-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={booking.from}
                  onChange={(e) => setBooking({...booking, from: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">إلى (نقطة الوصول)</label>
                <select 
                  className="w-full p-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={booking.to}
                  onChange={(e) => setBooking({...booking, to: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">تاريخ السفر</label>
                <input 
                  type="date"
                  className="w-full p-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={booking.date}
                  onChange={(e) => setBooking({...booking, date: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">توقع ميعاد الوصول</label>
                <input 
                  type="time"
                  className="w-full p-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={booking.arrivalTime}
                  onChange={(e) => setBooking({...booking, arrivalTime: e.target.value})}
                />
              </div>
            </div>
            <div className="pt-8 flex justify-end">
              <button 
                disabled={!booking.from || !booking.to || !booking.date}
                onClick={handleNext}
                className="bg-blue-900 text-white px-10 py-3 rounded-xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-lg"
              >
                التالي: نوع الباص
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Bus Type */}
        {step === 2 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">اختر نوع الحافلة</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {Object.values(BusType).map((type) => (
                <div 
                  key={type}
                  onClick={() => setBooking({...booking, busType: type})}
                  className={`cursor-pointer p-6 rounded-2xl border-2 transition-all flex flex-col items-center text-center gap-4
                    ${booking.busType === type ? 'border-amber-500 bg-amber-50 shadow-inner' : 'border-gray-100 hover:border-blue-200'}`}
                >
                  <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center text-blue-900">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
                    </svg>
                  </div>
                  <h4 className="font-bold text-lg">{type}</h4>
                  <p className="text-gray-500 text-sm">تبدأ من {BUS_PRICES[type]} ج.م</p>
                </div>
              ))}
            </div>
            <div className="pt-8 flex justify-between">
              <button onClick={handleBack} className="text-gray-600 font-bold hover:bg-gray-100 px-6 py-3 rounded-xl">رجوع</button>
              <button 
                onClick={handleNext}
                className="bg-blue-900 text-white px-10 py-3 rounded-xl font-bold hover:bg-blue-800 transition-all shadow-lg"
              >
                التالي: اختيار السائق
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Driver Selection */}
        {step === 3 && (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold text-gray-800">اختر سائق الرحلة</h3>
              <p className="text-amber-600 text-sm font-bold bg-amber-50 px-3 py-1 rounded-full border border-amber-200">كلما زاد تقييم السائق زاد سعر التذكرة لضمان الجودة</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {DRIVERS.map((d) => (
                <div 
                  key={d.id}
                  onClick={() => setBooking({...booking, driver: d})}
                  className={`cursor-pointer p-6 rounded-2xl border-2 transition-all flex items-center gap-4
                    ${booking.driver?.id === d.id ? 'border-amber-500 bg-amber-50' : 'border-gray-100 hover:border-blue-200'}`}
                >
                  <img src={d.photo} alt={d.name} className="w-20 h-20 rounded-xl object-cover" />
                  <div className="flex-1">
                    <h4 className="font-bold text-lg">{d.name}</h4>
                    <div className="flex items-center gap-1 text-amber-500 mb-1">
                      <span className="font-bold">{d.rating}</span>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 fill-current" viewBox="0 0 20 20">
                        <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                      </svg>
                    </div>
                    <p className="text-gray-500 text-xs">خبرة {d.experience}</p>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-8 flex justify-between">
              <button onClick={handleBack} className="text-gray-600 font-bold hover:bg-gray-100 px-6 py-3 rounded-xl">رجوع</button>
              <button 
                disabled={!booking.driver}
                onClick={handleNext}
                className="bg-blue-900 text-white px-10 py-3 rounded-xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-lg"
              >
                التالي: الدفع والتأكيد
              </button>
            </div>
          </div>
        )}

        {/* Step 4: Summary & Payment */}
        {step === 4 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">تأكيد الحجز والدفع</h3>
            <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100 mb-8 space-y-4">
              <div className="flex justify-between border-b border-blue-100 pb-2">
                <span className="text-blue-700">الرحلة:</span>
                <span className="font-bold">{booking.from} ← {booking.to}</span>
              </div>
              <div className="flex justify-between border-b border-blue-100 pb-2">
                <span className="text-blue-700">التاريخ:</span>
                <span className="font-bold">{booking.date}</span>
              </div>
              <div className="flex justify-between border-b border-blue-100 pb-2">
                <span className="text-blue-700">الوصول المتوقع:</span>
                <span className="font-bold">{booking.arrivalTime}</span>
              </div>
              <div className="flex justify-between border-b border-blue-100 pb-2">
                <span className="text-blue-700">نوع الباص والسائق:</span>
                <span className="font-bold">{booking.busType} - {booking.driver?.name}</span>
              </div>
              <div className="flex justify-between items-center pt-2">
                <span className="text-blue-900 font-bold text-xl">الإجمالي:</span>
                <span className="text-2xl font-black text-amber-600">{calculatePrice()} ج.م</span>
              </div>
            </div>

            <div className="space-y-4">
              <h4 className="font-bold text-gray-700">معلومات الدفع</h4>
              <div className="grid grid-cols-1 gap-4">
                <input type="text" placeholder="رقم البطاقة" className="w-full p-3 border rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="MM/YY" className="w-full p-3 border rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                  <input type="text" placeholder="CVV" className="w-full p-3 border rounded-xl outline-none focus:ring-2 focus:ring-blue-500" />
                </div>
              </div>
            </div>

            <div className="pt-8 flex justify-between">
              <button onClick={handleBack} className="text-gray-600 font-bold hover:bg-gray-100 px-6 py-3 rounded-xl">رجوع</button>
              <button 
                onClick={handleFinish}
                className="bg-green-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-green-700 transition-all shadow-lg"
              >
                إتمام الحجز الآن
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default BookingFlow;

import React, { useState } from 'react';
import { Complaint } from '../types';
import { analyzeComplaint } from '../services/geminiService';

const ComplaintSystem: React.FC = () => {
  const [complaints, setComplaints] = useState<Complaint[]>([]);
  const [subject, setSubject] = useState('');
  const [description, setDescription] = useState('');
  const [loading, setLoading] = useState(false);
  const [aiResponse, setAiResponse] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    // Simulate API Response from Gemini
    const response = await analyzeComplaint(subject, description);

    const newComplaint: Complaint = {
      id: Math.random().toString(36).substr(2, 9),
      userId: 'current-user',
      subject,
      description,
      date: new Date().toLocaleDateString('ar-EG'),
      status: 'pending'
    };

    setComplaints([newComplaint, ...complaints]);
    setAiResponse(response);
    setSubject('');
    setDescription('');
    setLoading(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold mb-6 text-gray-800">تقديم شكوى أو مقترح</h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">الموضوع</label>
              <input 
                type="text"
                required
                className="w-full p-3 border rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                value={subject}
                onChange={(e) => setSubject(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">التفاصيل</label>
              <textarea 
                required
                rows={5}
                className="w-full p-3 border rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
              />
            </div>
            <button 
              type="submit"
              disabled={loading}
              className="w-full bg-red-600 hover:bg-red-700 text-white py-3 rounded-xl font-bold transition-all disabled:opacity-50"
            >
              {loading ? 'جاري الإرسال...' : 'إرسال الشكوى'}
            </button>
          </form>

          {aiResponse && (
            <div className="mt-6 bg-green-50 border border-green-200 p-4 rounded-xl animate-fadeIn">
              <h4 className="text-green-800 font-bold mb-2 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd" />
                </svg>
                رد آلي فوري:
              </h4>
              <p className="text-green-700 text-sm leading-relaxed whitespace-pre-line">{aiResponse}</p>
            </div>
          )}
        </div>

        <div className="space-y-6">
          <h2 className="text-2xl font-bold text-gray-800">تاريخ شكاويك</h2>
          {complaints.length === 0 ? (
            <div className="text-center py-12 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-200 text-gray-400">
              لا توجد شكاوى سابقة
            </div>
          ) : (
            complaints.map(c => (
              <div key={c.id} className="bg-white p-5 rounded-xl shadow border border-gray-100">
                <div className="flex justify-between items-start mb-2">
                  <h4 className="font-bold text-gray-800">{c.subject}</h4>
                  <span className={`text-xs px-2 py-1 rounded-full ${c.status === 'pending' ? 'bg-amber-100 text-amber-700' : 'bg-green-100 text-green-700'}`}>
                    {c.status === 'pending' ? 'تحت المراجعة' : 'تم الحل'}
                  </span>
                </div>
                <p className="text-gray-500 text-sm mb-3 line-clamp-2">{c.description}</p>
                <span className="text-xs text-gray-400">{c.date}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default ComplaintSystem;

import React, { useState } from 'react';
import { Ticket } from '../types';

interface PastTripsProps {
  tickets: Ticket[];
  onRate: (id: string, rating: number, review: string) => void;
}

const PastTrips: React.FC<PastTripsProps> = ({ tickets, onRate }) => {
  const [ratingId, setRatingId] = useState<string | null>(null);
  const [rating, setRating] = useState(5);
  const [review, setReview] = useState('');

  const submitRating = () => {
    if (ratingId) {
      onRate(ratingId, rating, review);
      setRatingId(null);
      setRating(5);
      setReview('');
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <h2 className="text-3xl font-bold text-gray-800 mb-8">رحلاتي السابقة والحالية</h2>

      {tickets.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-3xl shadow-sm border border-gray-100">
          <p className="text-gray-400 text-lg">لم تقم بحجز أي رحلات بعد</p>
        </div>
      ) : (
        <div className="space-y-6">
          {tickets.map(t => (
            <div key={t.id} className="bg-white rounded-2xl shadow-lg border border-gray-100 overflow-hidden">
              <div className="bg-blue-900 p-4 text-white flex justify-between items-center">
                <span className="font-bold">تذكرة رقم: {t.id}</span>
                <span className={`px-3 py-1 rounded-full text-xs font-bold ${t.status === 'upcoming' ? 'bg-amber-500 text-blue-900' : 'bg-green-500 text-white'}`}>
                  {t.status === 'upcoming' ? 'قادمة' : 'مكتملة'}
                </span>
              </div>
              <div className="p-6">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-6">
                  <div className="flex items-center gap-8">
                    <div className="text-center">
                      <p className="text-xs text-gray-400 mb-1">من</p>
                      <p className="text-xl font-black text-blue-900">{t.from}</p>
                    </div>
                    <div className="flex flex-col items-center flex-1 min-w-[100px]">
                      <div className="w-full h-px bg-gray-200 relative">
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white px-2">
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-amber-500" viewBox="0 0 20 20" fill="currentColor">
                            <path d="M8 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0zM15 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0z" />
                            <path d="M3 4a1 1 0 00-1 1v10a1 1 0 001 1h1.05a2.5 2.5 0 014.9 0H10a1 1 0 011 1h1.05a2.5 2.5 0 014.9 0H18a1 1 0 001-1V5a1 1 0 00-1-1H3z" />
                          </svg>
                        </div>
                      </div>
                      <span className="text-[10px] text-gray-400 mt-2 font-bold">{t.busType}</span>
                    </div>
                    <div className="text-center">
                      <p className="text-xs text-gray-400 mb-1">إلى</p>
                      <p className="text-xl font-black text-blue-900">{t.to}</p>
                    </div>
                  </div>

                  <div className="text-right border-r pr-6 border-gray-100">
                    <p className="text-sm text-gray-500">التاريخ: <span className="font-bold text-gray-800">{t.date}</span></p>
                    <p className="text-sm text-gray-500">الوصول: <span className="font-bold text-gray-800">{t.arrivalTime}</span></p>
                    <p className="text-lg font-black text-amber-600 mt-2">{t.price} ج.م</p>
                  </div>
                </div>

                {t.status === 'completed' && !t.rating && (
                  <button 
                    onClick={() => setRatingId(t.id)}
                    className="w-full bg-amber-500 hover:bg-amber-600 text-blue-900 font-bold py-2 rounded-xl transition-all"
                  >
                    تقييم الرحلة والسائق
                  </button>
                )}

                {t.rating && (
                  <div className="bg-gray-50 p-4 rounded-xl">
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-sm font-bold text-gray-700">تقييمك:</span>
                      <div className="flex text-amber-500">
                        {Array.from({length: t.rating}).map((_, i) => (
                          <svg key={i} xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 fill-current" viewBox="0 0 20 20">
                            <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                          </svg>
                        ))}
                      </div>
                    </div>
                    {t.review && <p className="text-gray-500 text-sm italic">"{t.review}"</p>}
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Rating Modal */}
      {ratingId && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center p-4 z-[100] backdrop-blur-sm">
          <div className="bg-white rounded-3xl p-8 max-w-md w-full animate-popIn">
            <h3 className="text-2xl font-bold mb-6 text-center">كيف كانت رحلتك مع تاج باص؟</h3>

            <div className="flex justify-center gap-2 mb-8">
              {[1, 2, 3, 4, 5].map(star => (
                <button 
                  key={star}
                  onClick={() => setRating(star)}
                  className={`text-4xl transition-all ${star <= rating ? 'text-amber-500 scale-110' : 'text-gray-200'}`}
                >
                  ★
                </button>
              ))}
            </div>

            <textarea 
              className="w-full p-4 border rounded-2xl mb-6 outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="اكتب رأيك هنا (اختياري)..."
              rows={3}
              value={review}
              onChange={(e) => setReview(e.target.value)}
            />

            <div className="flex gap-4">
              <button 
                onClick={submitRating}
                className="flex-1 bg-blue-900 text-white font-bold py-3 rounded-xl hover:bg-blue-800 transition-all"
              >
                تأكيد
              </button>
              <button 
                onClick={() => setRatingId(null)}
                className="flex-1 bg-gray-100 text-gray-600 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all"
              >
                إلغاء
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PastTrips;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import AuthForm from './components/AuthForm';
import BookingFlow from './components/BookingFlow';
import ComplaintSystem from './components/ComplaintSystem';
import PastTrips from './components/PastTrips';
import { User, Ticket } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);

  // Load user from local storage (simplified)
  useEffect(() => {
    const savedUser = localStorage.getItem('tajbus_user');
    if (savedUser) setUser(JSON.parse(savedUser));

    // Some initial mock tickets
    setTickets([
      {
        id: 'TB-9921',
        userId: 'current-user',
        from: 'القاهرة',
        to: 'الإسكندرية',
        busType: 'اقتصادية' as any,
        driverId: 'd2',
        date: '2023-12-01',
        arrivalTime: '14:30',
        price: 180,
        status: 'completed',
        rating: 5,
        review: 'رحلة ممتازة وسائق محترف'
      }
    ]);
  }, []);

  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('tajbus_user', JSON.stringify(userData));
    setCurrentPage('home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('tajbus_user');
    setCurrentPage('home');
  };

  const handleBookingComplete = (ticket: Ticket) => {
    setTickets([ticket, ...tickets]);
    setCurrentPage('my-tickets');
    alert('تم الحجز بنجاح! شكراً لاختيارك تاج باص');
  };

  const handleRate = (id: string, rating: number, review: string) => {
    setTickets(prev => prev.map(t => t.id === id ? { ...t, rating, review } : t));
  };

  const renderPage = () => {
    if (currentPage === 'login') return <AuthForm onLogin={handleLogin} />;

    if (currentPage === 'complaints') {
      return user ? <ComplaintSystem /> : <AuthForm onLogin={handleLogin} />;
    }

    if (currentPage === 'my-tickets') {
      return user ? <PastTrips tickets={tickets} onRate={handleRate} /> : <AuthForm onLogin={handleLogin} />;
    }

    // Default Home / Booking
    return (
      <div className="container mx-auto">
        <header className="py-20 text-center space-y-6">
          <h1 className="text-5xl md:text-7xl font-black text-blue-900 leading-tight">
            سافر كالملوك مع <span className="text-amber-500">تاج باص</span>
          </h1>
          <p className="text-xl text-gray-500 max-w-2xl mx-auto">
            أول منصة تتيح لك اختيار حافلتك وسائقك حسب تقييمك الشخصي، لضمان أعلى مستويات الراحة والأمان في كل رحلة.
          </p>
        </header>

        <section id="booking">
          {user ? (
            <BookingFlow onComplete={handleBookingComplete} />
          ) : (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-3xl shadow-xl text-center border border-gray-100">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 text-amber-500 mx-auto mb-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
              </svg>
              <h3 className="text-2xl font-bold mb-4">يجب تسجيل الدخول للحجز</h3>
              <p className="text-gray-500 mb-8">سجل الآن لتتمكن من تصفح المواعيد المتاحة واختيار سائقك المفضل</p>
              <button 
                onClick={() => setCurrentPage('login')}
                className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-blue-800 transition-all shadow-xl"
              >
                ابدأ رحلتك الآن
              </button>
            </div>
          )}
        </section>

        <section className="py-24 px-4 grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="bg-blue-50 p-8 rounded-3xl border border-blue-100 text-center hover:-translate-y-2 transition-transform">
             <div className="text-4xl mb-4">🏆</div>
             <h4 className="text-xl font-bold text-blue-900 mb-2">نخبة السائقين</h4>
             <p className="text-blue-700/70 text-sm">نحن نوظف فقط أصحاب الخبرة والكفاءة العالية لضمان سلامتك.</p>
          </div>
          <div className="bg-amber-50 p-8 rounded-3xl border border-amber-100 text-center hover:-translate-y-2 transition-transform">
             <div className="text-4xl mb-4">🚌</div>
             <h4 className="text-xl font-bold text-amber-900 mb-2">أسطول ملكي</h4>
             <p className="text-amber-800/70 text-sm">حافلات حديثة مزودة بأعلى وسائل الراحة والترفيه والإنترنت.</p>
          </div>
          <div className="bg-green-50 p-8 rounded-3xl border border-green-100 text-center hover:-translate-y-2 transition-transform">
             <div className="text-4xl mb-4">⚡</div>
             <h4 className="text-xl font-bold text-green-900 mb-2">دفع آمن</h4>
             <p className="text-green-800/70 text-sm">نظام دفع إلكتروني متكامل وسريع يضمن خصوصية بياناتك.</p>
          </div>
        </section>
      </div>
    );
  };

  return (
    <div className="min-h-screen flex flex-col font-tajawal">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={setCurrentPage}
        currentPage={currentPage}
      />

      <main className="flex-grow">
        {renderPage()}
      </main>

      <footer className="bg-gray-900 text-gray-400 py-12 mt-20">
        <div className="container mx-auto px-4 text-center">
          <div className="text-2xl font-bold text-white mb-4">تاج باص Taj Bus</div>
          <p className="mb-8">الوجهة الأولى للسفر الفاخر والآمن في الوطن العربي.</p>
          <div className="border-t border-gray-800 pt-8 text-sm">
            © 2024 تاج باص. جميع الحقوق محفوظة.
          </div>
        </div>
      </footer>
    </div>
  );
};

