  const handleLogin = (userData: User) => {
    setUser(userData);
    localStorage.setItem('tajbus_user', JSON.stringify(userData));
    setCurrentPage('home');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('tajbus_user');
    setCurrentPage('home');
  };

  const handleBookingComplete = (ticket: Ticket) => {
    setTickets([ticket, ...tickets]);
    setCurrentPage('my-tickets');
  };

  const handleRate = (id: string, rating: number, review: string) => {
    setTickets(prev => prev.map(t => t.id === id ? { ...t, rating, review } : t));
  };

  const renderPage = () => {
    if (currentPage === 'login') return <AuthForm onLogin={handleLogin} />;

    if (currentPage === 'complaints') {
      return user ? <ComplaintSystem /> : <AuthForm onLogin={handleLogin} />;
    }

    if (currentPage === 'my-tickets') {
      return user ? <PastTrips tickets={tickets} onRate={handleRate} /> : <AuthForm onLogin={handleLogin} />;
    }

    return (
      <div className="container mx-auto px-4">
        <header className="py-16 md:py-24 text-center space-y-8 animate-fadeIn">
          <div className="inline-block p-4 bg-white rounded-full shadow-2xl mb-4 border-4 border-amber-100">
            <Logo size={120} />
          </div>
          <div className="space-y-4">
            <h1 className="text-5xl md:text-8xl font-black text-blue-900 leading-tight">
              سافر كالملوك مع <span className="text-amber-500 drop-shadow-sm">تاج باص</span>
            </h1>
            <p className="text-xl md:text-2xl text-gray-500 max-w-3xl mx-auto font-medium">
              أول منصة تتيح لك اختيار حافلتك وسائقك حسب تقييمك الشخصي، لضمان أعلى مستويات الراحة والأمان في كل رحلة.
            </p>
          </div>
          <div className="flex justify-center gap-4 pt-4">
            <button 
               onClick={() => {
                 const el = document.getElementById('booking');
                 el?.scrollIntoView({ behavior: 'smooth' });
               }}
               className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-blue-800 transition-all shadow-xl hover:-translate-y-1"
            >
              احجز رحلتك الآن
            </button>
            <button className="bg-white text-blue-900 border-2 border-blue-900 px-10 py-4 rounded-2xl font-black text-lg hover:bg-blue-50 transition-all">
              تعرف علينا
            </button>
          </div>
        </header>

        <section id="booking" className="scroll-mt-24">
          {user ? (
            <BookingFlow onComplete={handleBookingComplete} />
          ) : (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-[2.5rem] shadow-2xl text-center border border-gray-100">
              <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-8">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                </svg>
              </div>
              <h3 className="text-3xl font-bold mb-4 text-blue-900">يجب تسجيل الدخول للحجز</h3>
              <p className="text-gray-500 text-lg mb-10 leading-relaxed">سجل الآن لتتمكن من تصفح المواعيد المتاحة واختيار سائقك المفضل والاستمتاع بميزاتنا الحصرية.</p>
              <button 
                onClick={() => setCurrentPage('login')}
                className="bg-gradient-to-r from-blue-900 to-blue-800 text-white px-12 py-4 rounded-2xl font-black text-xl hover:shadow-2xl transition-all active:scale-95"
              >
                دخول / إنشاء حساب
              </button>
            </div>
          )}
        </section>

        <section className="py-24 grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-blue-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-blue-900 group-hover:text-white transition-colors">🏆</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">نخبة السائقين</h4>
             <p className="text-gray-500 text-sm leading-relaxed">نحن نوظف فقط أصحاب الخبرة والكفاءة العالية لضمان سلامتك وراحتك طوال الطريق.</p>
          </div>
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-amber-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-amber-500 group-hover:text-blue-900 transition-colors">🚌</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">أسطول ملكي</h4>
             <p className="text-gray-500 text-sm leading-relaxed">حافلات حديثة مزودة بأعلى وسائل الراحة، مقاعد جلدية، تكييف متطور وإنترنت مجاني.</p>
          </div>
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-green-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-green-600 group-hover:text-white transition-colors">⚡</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">دفع آمن وسريع</h4>
             <p className="text-gray-500 text-sm leading-relaxed">نظام دفع إلكتروني مشفر ومتكامل يضمن خصوصية بياناتك المالية وسرعة إتمام الحجز.</p>
          </div>
        </section>
      </div>
    );
  };

  return (
    <div className="min-h-screen flex flex-col font-tajawal selection:bg-amber-200 selection:text-blue-900">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={setCurrentPage}
        currentPage={currentPage}
      />

      <main className="flex-grow bg-[#fafbfc]">
        {renderPage()}
      </main>

      <footer className="bg-blue-950 text-blue-200 py-16">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row justify-between items-center gap-8 mb-12">
            <div className="flex items-center gap-4">
               <div className="bg-white p-2 rounded-xl">
                 <Logo size={40} />
               </div>
               <div>
                 <div className="text-2xl font-black text-white">تاج باص Taj Bus</div>
                 <p className="text-sm text-blue-300">نحن نعيد تعريف مفهوم السفر البري.</p>
               </div>
            </div>
            <div className="flex gap-6">
              <a href="#" className="hover:text-amber-500 transition-colors">عن الشركة</a>
              <a href="#" className="hover:text-amber-500 transition-colors">الشروط والأحكام</a>
              <a href="#" className="hover:text-amber-500 transition-colors">سياسة الخصوصية</a>
            </div>
          </div>
          <div className="border-t border-blue-900 pt-8 text-center text-sm text-blue-400">
            © 2024 تاج باص Taj Bus. جميع الحقوق محفوظة لشركة النقل الفاخر.
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum BusType {
  STANDARD = 'اقتصادية',
  VIP = 'كبار الشخصيات',
  ROYAL = 'رويال الملكية'
}

export interface Driver {
  id: string;
  name: string;
  rating: number;
  experience: string;
  photo: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  loggedIn: boolean;
}

export interface Ticket {
  id: string;
  userId: string;
  from: string;
  to: string;
  busType: BusType;
  driverId: string;
  date: string;
  arrivalTime: string;
  price: number;
  selectedSeats: number[];
  status: 'upcoming' | 'completed' | 'cancelled';
  rating?: number;
  review?: string;
}

export interface Complaint {
  id: string;
  userId: string;
  subject: string;
  description: string;
  date: string;
  status: 'pending' | 'resolved';
}

export interface BookingState {
  from: string;
  to: string;
  busType: BusType;
  driver: Driver | null;
  date: string;
  arrivalTime: string;
  selectedSeats: number[];
}

import React, { useState } from 'react';
import { CITIES, BUS_PRICES, DRIVERS } from '../constants';
import { BusType, Driver, BookingState, Ticket } from '../types';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [booking, setBooking] = useState<BookingState>({
    from: '',
    to: '',
    busType: BusType.STANDARD,
    driver: null,
    date: '',
    arrivalTime: '12:00',
    selectedSeats: []
  });

  const calculateUnitPrice = () => {
    const base = BUS_PRICES[booking.busType];
    const driverBonus = booking.driver ? (booking.driver.rating * 20) : 0;
    return base + driverBonus;
  };

  const totalPrice = calculateUnitPrice() * (booking.selectedSeats.length || 1);

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const toggleSeat = (seatNum: number) => {
    setBooking(prev => {
      const isSelected = prev.selectedSeats.includes(seatNum);
      if (isSelected) {
        return { ...prev, selectedSeats: prev.selectedSeats.filter(s => s !== seatNum) };
      } else {
        return { ...prev, selectedSeats: [...prev.selectedSeats, seatNum] };
      }
    });
  };

  const handleFinish = () => {
    const ticket: Ticket = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      userId: 'current-user',
      ...booking,
      driverId: booking.driver?.id || '',
      price: totalPrice,
      status: 'upcoming'
    };
    onComplete(ticket);
  };

  // Mock occupied seats
  const occupiedSeats = [5, 12, 18, 24];

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      {/* Progress Stepper */}
      <div className="flex items-center justify-between mb-12 relative px-4">
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-200 -z-10 -translate-y-1/2 mx-10"></div>
        {[1, 2, 3, 4, 5].map((i) => (
          <div 
            key={i}
            className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all border-2
              ${step >= i ? 'bg-blue-900 text-white border-blue-900' : 'bg-white text-gray-400 border-gray-200'}`}
          >
            {i}
          </div>
        ))}
      </div>

      <div className="bg-white rounded-3xl shadow-2xl p-8 border border-gray-100 min-h-[500px]">
        {/* Step 1: Destination & Date */}
        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">حدد وجهتك وموعدك</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">من (نقطة المغادرة)</label>
                <select 
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.from}
                  onChange={(e) => setBooking({...booking, from: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">إلى (نقطة الوصول)</label>
                <select 
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.to}
                  onChange={(e) => setBooking({...booking, to: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">تاريخ السفر</label>
                <input 
                  type="date"
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.date}
                  onChange={(e) => setBooking({...booking, date: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">ميعاد الوصول المفضل</label>
                <input 
                  type="time"
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.arrivalTime}
                  onChange={(e) => setBooking({...booking, arrivalTime: e.target.value})}
                />
              </div>
            </div>
            <div className="pt-10 flex justify-end">
              <button 
                disabled={!booking.from || !booking.to || !booking.date}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                استمرار لخطوة نوع الباص
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Bus Type */}
        {step === 2 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">اختر نوع الخدمة</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {Object.values(BusType).map((type) => (
                <div 
                  key={type}
                  onClick={() => setBooking({...booking, busType: type})}
                  className={`cursor-pointer p-8 rounded-[2rem] border-2 transition-all flex flex-col items-center text-center gap-4
                    ${booking.busType === type ? 'border-amber-500 bg-amber-50 shadow-lg' : 'border-gray-100 hover:border-blue-200 bg-white'}`}
                >
                  <div className={`w-20 h-20 rounded-full flex items-center justify-center ${booking.busType === type ? 'bg-amber-500 text-white' : 'bg-blue-50 text-blue-900'}`}>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
                    </svg>
                  </div>
                  <h4 className="font-black text-xl">{type}</h4>
                  <p className="text-gray-500 font-medium">سعر المقعد: {BUS_PRICES[type]} ج.م</p>
                </div>
              ))}
            </div>
            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold hover:bg-blue-800 transition-all shadow-xl"
              >
                اختيار السائق
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Driver Selection */}
        {step === 3 && (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
              <h3 className="text-2xl font-bold text-gray-800">اختر سائقك المفضل</h3>
              <div className="bg-amber-100 text-amber-800 text-xs font-black px-4 py-2 rounded-full border border-amber-200 animate-pulse">
                زيادة التقييم ترفع جودة الخدمة والسعر
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {DRIVERS.map((d) => (
                <div 
                  key={d.id}
                  onClick={() => setBooking({...booking, driver: d})}
                  className={`cursor-pointer p-6 rounded-3xl border-2 transition-all flex items-center gap-6
                    ${booking.driver?.id === d.id ? 'border-amber-500 bg-amber-50 shadow-md' : 'border-gray-50 bg-white hover:border-blue-100'}`}
                >
                  <div className="relative">
                    <img src={d.photo} alt={d.name} className="w-24 h-24 rounded-2xl object-cover shadow-sm" />
                    <div className="absolute -top-2 -right-2 bg-amber-500 text-white text-[10px] font-bold px-2 py-1 rounded-lg">
                      {d.rating} ★
                    </div>
                  </div>
                  <div className="flex-1">
                    <h4 className="font-black text-xl text-blue-900">{d.name}</h4>
                    <p className="text-gray-500 text-sm font-bold mb-2">خبرة {d.experience}</p>
                    <div className="flex gap-1">
                      {[1,2,3,4,5].map(s => (
                        <div key={s} className={`w-2 h-2 rounded-full ${s <= Math.floor(d.rating) ? 'bg-amber-500' : 'bg-gray-200'}`}></div>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                disabled={!booking.driver}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                اختيار المقاعد
              </button>
            </div>
          </div>
        )}

        {/* Step 4: Seat Selection (New) */}
        {step === 4 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="flex justify-between items-end">
              <div>
                <h3 className="text-2xl font-bold text-gray-800 mb-2">اختر مقاعدك</h3>
                <p className="text-gray-500">لقد اخترت {booking.selectedSeats.length} مقاعد</p>
              </div>
              <div className="flex gap-4 text-xs font-bold">
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-gray-100 rounded"></div> متاح</div>
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-amber-500 rounded"></div> مختار</div>
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-gray-400 rounded"></div> محجوز</div>
              </div>
            </div>

            <div className="bg-gray-50 p-10 rounded-[3rem] max-w-sm mx-auto border-4 border-gray-200 shadow-inner relative">
              {/* Bus Driver Area */}
              <div className="absolute top-4 left-1/2 -translate-x-1/2 w-20 h-10 border-b-4 border-gray-300 flex items-center justify-center text-[10px] font-bold text-gray-400">
                مقدمة الحافلة
              </div>

              <div className="grid grid-cols-4 gap-4 mt-8">
                {Array.from({length: 40}, (_, i) => i + 1).map(seat => {
                  const isOccupied = occupiedSeats.includes(seat);
                  const isSelected = booking.selectedSeats.includes(seat);
                  const isAisle = (seat - 2) % 4 === 1; // Simple logic for aisle after 2 seats

                  return (
                    <React.Fragment key={seat}>
                      <button
                        disabled={isOccupied}
                        onClick={() => toggleSeat(seat)}
                        className={`w-10 h-12 rounded-lg font-bold text-xs transition-all flex items-center justify-center
                          ${isOccupied ? 'bg-gray-400 text-white cursor-not-allowed' : 
                            isSelected ? 'bg-amber-500 text-blue-900 shadow-lg scale-110' : 'bg-white text-gray-400 border border-gray-200 hover:border-amber-400'}
                        `}
                      >
                        {seat}
                      </button>
                      {isAisle && <div className="w-4"></div>}
                    </React.Fragment>
                  );
                })}
              </div>
            </div>

            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                disabled={booking.selectedSeats.length === 0}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                مراجعة الحجز والدفع
              </button>
            </div>
          </div>
        )}

        {/* Step 5: Summary & Payment */}
        {step === 5 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6 text-center">تفاصيل الرحلة النهائية</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="bg-blue-50 p-8 rounded-[2rem] border border-blue-100 space-y-4 shadow-sm">
                <div className="flex justify-between items-center border-b border-blue-100 pb-3">
                  <span className="text-blue-700 font-medium">خط السير:</span>
                  <span className="font-black text-blue-900">{booking.from} ← {booking.to}</span>
                </div>
                <div className="flex justify-between items-center border-b border-blue-100 pb-3">
                  <span className="text-blue-700 font-medium">التاريخ والوقت:</span>
                  <span className="font-bold text-blue-900">{booking.date} | {booking.arrivalTime}</span>
                </div>
                <div className="flex justify-between items-center border-b border-blue-100 pb-3">
                  <span className="text-blue-700 font-medium">نوع الخدمة:</span>
                  <span className="font-bold text-blue-900">{booking.busType}</span>
                </div>
                <div className="flex justify-between items-center border-b border-blue-100 pb-3">
                  <span className="text-blue-700 font-medium">السائق:</span>
                  <span className="font-bold text-blue-900">{booking.driver?.name}</span>
                </div>
                <div className="flex justify-between items-center border-b border-blue-100 pb-3">
                  <span className="text-blue-700 font-medium">المقاعد المختارة:</span>
                  <div className="flex gap-2">
                    {booking.selectedSeats.map(s => (
                      <span key={s} className="bg-blue-900 text-white px-2 py-1 rounded-lg text-xs font-bold">{s}</span>
                    ))}
                  </div>
                </div>
                <div className="flex justify-between items-center pt-4">
                  <span className="text-2xl font-black text-blue-900">الإجمالي:</span>
                  <span className="text-3xl font-black text-amber-600 underline decoration-amber-200">{totalPrice} ج.م</span>
                </div>
              </div>

              <div className="space-y-6">
                <h4 className="font-black text-xl text-gray-800">بيانات بطاقة الدفع</h4>
                <div className="space-y-4">
                  <input type="text" placeholder="اسم صاحب البطاقة" className="w-full p-4 border-2 border-gray-100 rounded-2xl outline-none focus:border-blue-500 transition-colors" />
                  <input type="text" placeholder="رقم البطاقة (16 رقم)" className="w-full p-4 border-2 border-gray-100 rounded-2xl outline-none focus:border-blue-500 transition-colors" />
                  <div className="grid grid-cols-2 gap-4">
                    <input type="text" placeholder="MM/YY" className="w-full p-4 border-2 border-gray-100 rounded-2xl outline-none focus:border-blue-500 transition-colors" />
                    <input type="text" placeholder="CVV" className="w-full p-4 border-2 border-gray-100 rounded-2xl outline-none focus:border-blue-500 transition-colors" />
                  </div>
                </div>
                <p className="text-[10px] text-gray-400 text-center italic">جميع المعاملات المالية مشفرة وتتم في بيئة آمنة تماماً.</p>
              </div>
            </div>

            <div className="pt-12 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                onClick={handleFinish}
                className="bg-green-600 text-white px-16 py-4 rounded-2xl font-black text-xl hover:bg-green-700 transition-all shadow-2xl active:scale-95"
              >
                تأكيد الدفع والحجز
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default BookingFlow;

