import React, { useState } from 'react';
import { CITIES, BUS_PRICES, DRIVERS } from '../constants';
import { BusType, Driver, BookingState, Ticket } from '../types';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [booking, setBooking] = useState<BookingState>({
    from: '',
    to: '',
    busType: BusType.STANDARD,
    driver: null,
    date: '',
    arrivalTime: '12:00',
    selectedSeats: []
  });

  const calculateUnitPrice = () => {
    const base = BUS_PRICES[booking.busType];
    const driverBonus = booking.driver ? (booking.driver.rating * 20) : 0;
    return base + driverBonus;
  };

  const unitPrice = calculateUnitPrice();
  const seatsCount = booking.selectedSeats.length || 1;
  const totalPrice = unitPrice * seatsCount;

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const toggleSeat = (seatNum: number) => {
    setBooking(prev => {
      const isSelected = prev.selectedSeats.includes(seatNum);
      if (isSelected) {
        return { ...prev, selectedSeats: prev.selectedSeats.filter(s => s !== seatNum) };
      } else {
        return { ...prev, selectedSeats: [...prev.selectedSeats, seatNum] };
      }
    });
  };

  const handleFinish = () => {
    const ticket: Ticket = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      userId: 'current-user',
      ...booking,
      driverId: booking.driver?.id || '',
      price: totalPrice,
      status: 'upcoming'
    };
    onComplete(ticket);
  };

  // Mock occupied seats
  const occupiedSeats = [5, 12, 18, 24];

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      {/* Progress Stepper */}
      <div className="flex items-center justify-between mb-12 relative px-4">
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-200 -z-10 -translate-y-1/2 mx-10"></div>
        {[1, 2, 3, 4, 5].map((i) => (
          <div 
            key={i}
            className={`w-10 h-10 rounded-full flex items-center justify-center font-bold transition-all border-2
              ${step >= i ? 'bg-blue-900 text-white border-blue-900' : 'bg-white text-gray-400 border-gray-200'}`}
          >
            {i}
          </div>
        ))}
      </div>

      <div className="bg-white rounded-3xl shadow-2xl p-8 border border-gray-100 min-h-[500px]">
        {/* Step 1: Destination & Date */}
        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">حدد وجهتك وموعدك</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">من (نقطة المغادرة)</label>
                <select 
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50 text-right"
                  value={booking.from}
                  onChange={(e) => setBooking({...booking, from: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">إلى (نقطة الوصول)</label>
                <select 
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50 text-right"
                  value={booking.to}
                  onChange={(e) => setBooking({...booking, to: e.target.value})}
                >
                  <option value="">اختر مدينة</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">تاريخ السفر</label>
                <input 
                  type="date"
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.date}
                  onChange={(e) => setBooking({...booking, date: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-600 mb-2">ميعاد الوصول المفضل</label>
                <input 
                  type="time"
                  className="w-full p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-gray-50"
                  value={booking.arrivalTime}
                  onChange={(e) => setBooking({...booking, arrivalTime: e.target.value})}
                />
              </div>
            </div>
            <div className="pt-10 flex justify-end">
              <button 
                disabled={!booking.from || !booking.to || !booking.date}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                استمرار لخطوة نوع الباص
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Bus Type */}
        {step === 2 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-bold text-gray-800 mb-6">اختر نوع الخدمة</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {Object.values(BusType).map((type) => (
                <div 
                  key={type}
                  onClick={() => setBooking({...booking, busType: type})}
                  className={`cursor-pointer p-8 rounded-[2rem] border-2 transition-all flex flex-col items-center text-center gap-4
                    ${booking.busType === type ? 'border-amber-500 bg-amber-50 shadow-lg' : 'border-gray-100 hover:border-blue-200 bg-white'}`}
                >
                  <div className={`w-20 h-20 rounded-full flex items-center justify-center ${booking.busType === type ? 'bg-amber-500 text-white' : 'bg-blue-50 text-blue-900'}`}>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" />
                    </svg>
                  </div>
                  <h4 className="font-black text-xl">{type}</h4>
                  <p className="text-gray-500 font-medium">سعر المقعد: {BUS_PRICES[type]} ج.م</p>
                </div>
              ))}
            </div>
            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold hover:bg-blue-800 transition-all shadow-xl"
              >
                اختيار السائق
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Driver Selection */}
        {step === 3 && (
          <div className="space-y-6 animate-fadeIn">
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
              <h3 className="text-2xl font-bold text-gray-800">اختر سائقك المفضل</h3>
              <div className="bg-amber-100 text-amber-800 text-xs font-black px-4 py-2 rounded-full border border-amber-200 animate-pulse">
                زيادة التقييم ترفع جودة الخدمة والسعر
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {DRIVERS.map((d) => (
                <div 
                  key={d.id}
                  onClick={() => setBooking({...booking, driver: d})}
                  className={`cursor-pointer p-6 rounded-3xl border-2 transition-all flex items-center gap-6
                    ${booking.driver?.id === d.id ? 'border-amber-500 bg-amber-50 shadow-md' : 'border-gray-50 bg-white hover:border-blue-100'}`}
                >
                  <div className="relative">
                    <img src={d.photo} alt={d.name} className="w-24 h-24 rounded-2xl object-cover shadow-sm" />
                    <div className="absolute -top-2 -right-2 bg-amber-500 text-white text-[10px] font-bold px-2 py-1 rounded-lg">
                      {d.rating} ★
                    </div>
                  </div>
                  <div className="flex-1">
                    <h4 className="font-black text-xl text-blue-900">{d.name}</h4>
                    <p className="text-gray-500 text-sm font-bold mb-2">خبرة {d.experience}</p>
                    <div className="flex gap-1">
                      {[1,2,3,4,5].map(s => (
                        <div key={s} className={`w-2 h-2 rounded-full ${s <= Math.floor(d.rating) ? 'bg-amber-500' : 'bg-gray-200'}`}></div>
                      ))}
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                disabled={!booking.driver}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                اختيار المقاعد
              </button>
            </div>
          </div>
        )}

        {/* Step 4: Seat Selection */}
        {step === 4 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="flex justify-between items-end">
              <div>
                <h3 className="text-2xl font-bold text-gray-800 mb-2">اختر مقاعدك</h3>
                <p className="text-gray-500 font-medium">لقد قمت بتحديد <span className="text-blue-900 font-black">{booking.selectedSeats.length}</span> مقاعد حتى الآن</p>
              </div>
              <div className="flex gap-4 text-xs font-bold">
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-gray-100 rounded"></div> متاح</div>
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-amber-500 rounded"></div> مختار</div>
                <div className="flex items-center gap-2"><div className="w-4 h-4 bg-gray-400 rounded"></div> محجوز</div>
              </div>
            </div>

            <div className="bg-gray-50 p-10 rounded-[3rem] max-w-sm mx-auto border-4 border-gray-200 shadow-inner relative">
              <div className="absolute top-4 left-1/2 -translate-x-1/2 w-20 h-10 border-b-4 border-gray-300 flex items-center justify-center text-[10px] font-bold text-gray-400">
                مقدمة الحافلة
              </div>

              <div className="grid grid-cols-4 gap-4 mt-8">
                {Array.from({length: 40}, (_, i) => i + 1).map(seat => {
                  const isOccupied = occupiedSeats.includes(seat);
                  const isSelected = booking.selectedSeats.includes(seat);
                  const isAisle = (seat - 2) % 4 === 1;

                  return (
                    <React.Fragment key={seat}>
                      <button
                        disabled={isOccupied}
                        onClick={() => toggleSeat(seat)}
                        className={`w-10 h-12 rounded-lg font-bold text-xs transition-all flex items-center justify-center
                          ${isOccupied ? 'bg-gray-400 text-white cursor-not-allowed' : 
                            isSelected ? 'bg-amber-500 text-blue-900 shadow-lg scale-110' : 'bg-white text-gray-400 border border-gray-200 hover:border-amber-400'}
                        `}
                      >
                        {seat}
                      </button>
                      {isAisle && <div className="w-4"></div>}
                    </React.Fragment>
                  );
                })}
              </div>
            </div>

            <div className="pt-10 flex justify-between">
              <button onClick={handleBack} className="text-gray-500 font-bold hover:bg-gray-100 px-8 py-4 rounded-2xl">رجوع</button>
              <button 
                disabled={booking.selectedSeats.length === 0}
                onClick={handleNext}
                className="bg-blue-900 text-white px-12 py-4 rounded-2xl font-bold disabled:opacity-50 hover:bg-blue-800 transition-all shadow-xl"
              >
                مراجعة الحجز والدفع
              </button>
            </div>
          </div>
