               className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-blue-800 transition-all shadow-xl hover:-translate-y-1"
            >
              احجز رحلتك الآن
            </button>
            <button className="bg-white text-blue-900 border-2 border-blue-900 px-10 py-4 rounded-2xl font-black text-lg hover:bg-blue-50 transition-all">
              تعرف علينا
            </button>
          </div>
        </header>

        <section id="booking" className="scroll-mt-24">
          {user ? (
            <BookingFlow onComplete={handleBookingComplete} />
          ) : (
            <div className="max-w-2xl mx-auto bg-white p-12 rounded-[2.5rem] shadow-2xl text-center border border-gray-100">
              <div className="w-24 h-24 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-8">
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                </svg>
              </div>
              <h3 className="text-3xl font-bold mb-4 text-blue-900">يجب تسجيل الدخول للحجز</h3>
              <p className="text-gray-500 text-lg mb-10 leading-relaxed">سجل الآن لتتمكن من تصفح المواعيد المتاحة واختيار سائقك المفضل والاستمتاع بميزاتنا الحصرية.</p>
              <button 
                onClick={() => setCurrentPage('login')}
                className="bg-gradient-to-r from-blue-900 to-blue-800 text-white px-12 py-4 rounded-2xl font-black text-xl hover:shadow-2xl transition-all active:scale-95"
              >
                دخول / إنشاء حساب
              </button>
            </div>
          )}
        </section>

        <section className="py-24 grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-blue-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-blue-900 group-hover:text-white transition-colors">🏆</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">نخبة السائقين</h4>
             <p className="text-gray-500 text-sm leading-relaxed">نحن نوظف فقط أصحاب الخبرة والكفاءة العالية لضمان سلامتك وراحتك طوال الطريق.</p>
          </div>
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-amber-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-amber-500 group-hover:text-blue-900 transition-colors">🚌</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">أسطول ملكي</h4>
             <p className="text-gray-500 text-sm leading-relaxed">حافلات حديثة مزودة بأعلى وسائل الراحة، مقاعد جلدية، تكييف متطور وإنترنت مجاني.</p>
          </div>
          <div className="group bg-white p-10 rounded-[2rem] border border-gray-100 text-center shadow-xl hover:shadow-2xl hover:-translate-y-3 transition-all">
             <div className="w-16 h-16 bg-green-50 text-3xl rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:bg-green-600 group-hover:text-white transition-colors">⚡</div>
             <h4 className="text-xl font-bold text-blue-900 mb-3">دفع آمن وسريع</h4>
             <p className="text-gray-500 text-sm leading-relaxed">نظام دفع إلكتروني مشفر ومتكامل يضمن خصوصية بياناتك المالية وسرعة إتمام الحجز.</p>
          </div>
        </section>
      </div>
    );
  };

  return (
    <div className="min-h-screen flex flex-col font-tajawal selection:bg-amber-200 selection:text-blue-900">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={setCurrentPage}
        currentPage={currentPage}
      />

      <main className="flex-grow bg-[#fafbfc]">
        {renderPage()}
      </main>

      <footer className="bg-blue-950 text-blue-200 py-16">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row justify-between items-center gap-8 mb-12">
