import React, { useState } from 'react';
import { Ticket } from '../types';

interface PastTripsProps {
  tickets: Ticket[];
  onRate: (id: string, rating: number, review: string) => void;
}

const PastTrips: React.FC<PastTripsProps> = ({ tickets, onRate }) => {
  const [ratingId, setRatingId] = useState<string | null>(null);
  const [rating, setRating] = useState(5);
  const [review, setReview] = useState('');

  const submitRating = () => {
    if (ratingId) {
      onRate(ratingId, rating, review);
      setRatingId(null);
      setRating(5);
      setReview('');
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-3xl font-black text-blue-900">سجل رحلاتي</h2>
        <div className="bg-blue-50 text-blue-900 px-4 py-2 rounded-2xl text-sm font-bold border border-blue-100">
          إجمالي الرحلات: {tickets.length}
        </div>
      </div>

      {tickets.length === 0 ? (
        <div className="text-center py-24 bg-white rounded-[3rem] shadow-xl border border-gray-100">
          <div className="text-6xl mb-4 opacity-20">🎫</div>
          <p className="text-gray-400 text-lg font-bold">لم تقم بحجز أي رحلات حتى الآن</p>
          <button className="mt-6 text-blue-600 font-bold hover:underline">ابدأ حجز رحلتك الأولى الآن</button>
        </div>
      ) : (
        <div className="space-y-8">
          {tickets.map(t => (
            <div key={t.id} className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-100 overflow-hidden hover:shadow-blue-900/10 transition-shadow group">
              <div className="bg-blue-900 p-5 text-white flex justify-between items-center">
                <div className="flex flex-col">
                  <span className="text-[10px] text-blue-300 font-bold tracking-widest uppercase">TICKET NUMBER</span>
                  <span className="font-black text-xl tracking-tighter">{t.id}</span>
                </div>
                <div className="flex items-center gap-4">
                   <span className={`px-4 py-1.5 rounded-full text-xs font-black uppercase ${t.status === 'upcoming' ? 'bg-amber-500 text-blue-900' : 'bg-green-500 text-white'}`}>
                    {t.status === 'upcoming' ? 'قادمة قريباً' : 'رحلة مكتملة'}
                  </span>
                </div>
              </div>
              <div className="p-8">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-10 mb-8">
                  <div className="flex items-center gap-12">
                    <div className="text-center">
                      <p className="text-[10px] text-gray-400 font-bold mb-2 uppercase tracking-widest">DEPARTURE</p>
                      <p className="text-2xl font-black text-blue-900 leading-none">{t.from}</p>
                    </div>
                    <div className="flex flex-col items-center flex-1 min-w-[140px]">
                      <div className="w-full h-px bg-dashed border-t-2 border-gray-100 border-dashed relative">
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white px-3">
                           <div className="w-10 h-10 bg-amber-50 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-amber-500" viewBox="0 0 20 20" fill="currentColor">
                              <path d="M8 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0zM15 16.5a1.5 1.5 0 11-3 0 1.5 1.5 0 013 0z" />
                              <path d="M3 4a1 1 0 00-1 1v10a1 1 0 001 1h1.05a2.5 2.5 0 014.9 0H10a1 1 0 011 1h1.05a2.5 2.5 0 014.9 0H18a1 1 0 001-1V5a1 1 0 00-1-1H3z" />
                            </svg>
                           </div>
                        </div>
                      </div>
                      <span className="text-[10px] text-amber-600 mt-4 font-black bg-amber-50 px-2 py-0.5 rounded border border-amber-100">{t.busType}</span>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] text-gray-400 font-bold mb-2 uppercase tracking-widest">ARRIVAL</p>
                      <p className="text-2xl font-black text-blue-900 leading-none">{t.to}</p>
                    </div>
                  </div>

                  <div className="flex flex-col items-end border-r-2 pr-10 border-gray-50">
                    <p className="text-sm text-gray-500 mb-1">تاريخ السفر: <span className="font-black text-blue-900">{t.date}</span></p>
                    <p className="text-sm text-gray-500 mb-4">وقت الوصول: <span className="font-black text-blue-900">{t.arrivalTime}</span></p>
                    <div className="flex items-center gap-3">
                      <span className="text-[10px] font-bold text-gray-400 uppercase">Total Price</span>
                      <p className="text-3xl font-black text-amber-600">{t.price} ج.م</p>
