                  </div>
                </div>

                <div className="flex flex-wrap items-center justify-between gap-4 pt-6 border-t border-gray-50">
                   <div className="flex items-center gap-3">
                     <span className="text-xs font-bold text-gray-400">المقاعد المحجوزة:</span>
                     <div className="flex gap-2">
                       {t.selectedSeats && t.selectedSeats.length > 0 ? t.selectedSeats.map(s => (
                         <span key={s} className="bg-blue-50 text-blue-900 px-3 py-1 rounded-xl text-sm font-black border border-blue-100">
