                         </span>
                       )) : <span className="text-gray-300 italic">لم يتم تحديد مقعد</span>}
                     </div>
                   </div>

                   {t.status === 'completed' && !t.rating && (
                    <button 
                      onClick={() => setRatingId(t.id)}
