                    <div className="bg-blue-50/50 p-4 rounded-2xl flex items-center gap-6">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-blue-400 font-bold mb-1 uppercase tracking-tighter">Your Rating</span>
                        <div className="flex text-amber-500">
                          {Array.from({length: t.rating}).map((_, i) => (
                            <svg key={i} xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 fill-current" viewBox="0 0 20 20">
                              <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                            </svg>
                          ))}
                        </div>
                      </div>
                      {t.review && <p className="text-gray-500 text-sm italic font-medium border-l border-blue-100 pl-6">"{t.review}"</p>}
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Rating Modal */}
      {ratingId && (
        <div className="fixed inset-0 bg-blue-950/60 flex items-center justify-center p-4 z-[100] backdrop-blur-md">
          <div className="bg-white rounded-[3rem] p-10 max-w-md w-full animate-popIn shadow-2xl">
            <h3 className="text-3xl font-black mb-2 text-center text-blue-900">كيف كانت رحلتك؟</h3>
            <p className="text-gray-400 text-center mb-10 font-medium">رأيك يهمنا لتحسين تجربة تاج باص</p>

            <div className="flex justify-center gap-3 mb-10">
              {[1, 2, 3, 4, 5].map(star => (
                <button 
                  key={star}
                  onClick={() => setRating(star)}
                  className={`text-5xl transition-all ${star <= rating ? 'text-amber-500 scale-125 drop-shadow-lg' : 'text-gray-100'}`}
                >
                  ★
                </button>
              ))}
            </div>

            <textarea 
              className="w-full p-6 bg-gray-50 border-2 border-gray-100 rounded-3xl mb-8 outline-none focus:border-amber-400 transition-colors text-right"
              placeholder="اكتب انطباعك عن السائق والحافلة..."
              rows={4}
              value={review}
              onChange={(e) => setReview(e.target.value)}
            />

            <div className="flex gap-4">
              <button 
                onClick={submitRating}
                className="flex-1 bg-blue-900 text-white font-black py-4 rounded-2xl hover:bg-blue-800 transition-all shadow-xl active:scale-95"
              >
                إرسال التقييم
              </button>
              <button 
                onClick={() => setRatingId(null)}
                className="flex-1 bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all"
              >
                إلغاء
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

