import React, { useState } from 'react';
import { CITIES, BUS_PRICES, DRIVERS } from '../constants';
import { BusType, BookingState, Ticket } from '../types';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [booking, setBooking] = useState<BookingState>({
    from: '', to: '', busType: BusType.STANDARD, driver: null, date: '', arrivalTime: '12:00', selectedSeats: []
  });

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const toggleSeat = (seat: number) => {
    setBooking(prev => ({
      ...prev,
      selectedSeats: prev.selectedSeats.includes(seat) ? prev.selectedSeats.filter(s => s !== seat) : [...prev.selectedSeats, seat]
    }));
  };

  const handleFinish = () => {
    onComplete({
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      userId: 'user-1', ...booking, driverId: booking.driver?.id || '',
      price: BUS_PRICES[booking.busType] * (booking.selectedSeats.length || 1),
      status: 'upcoming'
    });
  };

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-10 border border-gray-100">
        {step === 1 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-black text-blue-900">أين تريد الذهاب؟</h3>
            <div className="grid grid-cols-2 gap-4">
              <select className="p-4 rounded-xl bg-gray-50 border" onChange={e => setBooking({...booking, from: e.target.value})}>
                <option>من مدينة</option>
                {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <select className="p-4 rounded-xl bg-gray-50 border" onChange={e => setBooking({...booking, to: e.target.value})}>
                <option>إلى مدينة</option>
                {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <input type="date" className="w-full p-4 rounded-xl bg-gray-50 border" onChange={e => setBooking({...booking, date: e.target.value})} />
            <button onClick={handleNext} className="w-full bg-blue-900 text-white py-4 rounded-xl font-black">التالي</button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-black text-blue-900">اختر نوع الحافلة</h3>
            <div className="grid grid-cols-3 gap-4">
              {Object.values(BusType).map(t => (
                <div key={t} onClick={() => setBooking({...booking, busType: t})} className={`p-6 border-2 rounded-2xl cursor-pointer text-center ${booking.busType === t ? 'border-amber-500 bg-amber-50' : ''}`}>
                  <span className="font-bold">{t}</span>
                </div>
              ))}
            </div>
            <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-4 rounded-xl">رجوع</button>
              <button onClick={handleNext} className="flex-2 bg-blue-900 text-white py-4 px-10 rounded-xl font-black">اختيار السائق</button>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-black text-blue-900">اختر سائقك</h3>
            <div className="grid grid-cols-2 gap-4">
              {DRIVERS.map(d => (
                <div key={d.id} onClick={() => setBooking({...booking, driver: d})} className={`flex items-center gap-4 p-4 border-2 rounded-2xl cursor-pointer ${booking.driver?.id === d.id ? 'border-amber-500 bg-amber-50' : ''}`}>
                  <img src={d.photo} className="w-12 h-12 rounded-full" />
                  <div><p className="font-black text-sm">{d.name}</p><p className="text-xs text-gray-400">{d.rating} ★</p></div>
                </div>
              ))}
            </div>
            <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-4 rounded-xl">رجوع</button>
              <button onClick={handleNext} disabled={!booking.driver} className="flex-2 bg-blue-900 text-white py-4 px-10 rounded-xl font-black disabled:opacity-50">اختيار المقاعد</button>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 text-center">
             <h3 className="text-2xl font-black text-blue-900">اختر مقعدك</h3>
             <div className="grid grid-cols-4 gap-2 max-w-xs mx-auto">
               {Array.from({length: 20}, (_, i) => i + 1).map(s => (
                 <button key={s} onClick={() => toggleSeat(s)} className={`p-3 rounded-lg border font-bold ${booking.selectedSeats.includes(s) ? 'bg-amber-500 text-white' : 'bg-gray-50'}`}>{s}</button>
               ))}
             </div>
             <div className="flex gap-4 pt-6">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-4 rounded-xl">رجوع</button>
              <button onClick={handleFinish} className="flex-2 bg-green-600 text-white py-4 px-10 rounded-xl font-black">تأكيد الحجز</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { analyzeComplaint } from '../services/geminiService';

const ComplaintSystem: React.FC = () => {
  const [subject, setSubject] = useState('');
  const [desc, setDesc] = useState('');
  const [aiResp, setAiResp] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const send = async (e: React.FormEvent) => {
