    setLoading(false);
  };

  return (
    <div className="max-w-2xl mx-auto py-12 px-4">
      <div className="bg-white p-10 rounded-[2.5rem] shadow-xl border">
        <h2 className="text-2xl font-black text-blue-900 mb-6">تقديم شكوى</h2>
        <form onSubmit={send} className="space-y-4">
          <input type="text" placeholder="الموضوع" className="w-full p-4 bg-gray-50 rounded-xl border" value={subject} onChange={e => setSubject(e.target.value)} required />
          <textarea placeholder="التفاصيل" className="w-full p-4 bg-gray-50 rounded-xl border" rows={4} value={desc} onChange={e => setDesc(e.target.value)} required />
          <button type="submit" disabled={loading} className="w-full bg-red-600 text-white py-4 rounded-xl font-bold">{loading ? 'جاري الإرسال...' : 'إرسال'}</button>
        </form>
        {aiResp && (
          <div className="mt-8 p-6 bg-green-50 border border-green-200 rounded-2xl animate-fadeIn">
            <p className="text-green-800 text-sm font-medium">{aiResp}</p>
          </div>
        )}
      </div>
    </div>
  );
};

