import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import AuthForm from './components/AuthForm';
import BookingFlow from './components/BookingFlow';
import PastTrips from './components/PastTrips';
import { User, Ticket } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);

  const handleLogin = (u: User) => { setUser(u); setCurrentPage('home'); };
  const handleLogout = () => { setUser(null); setCurrentPage('home'); };

  const addTicket = (t: Ticket) => { 
    setTickets([t, ...tickets]); 
    setCurrentPage('my-tickets'); 
  };

  const handleRateTicket = (id: string, rating: number, review: string) => {
    setTickets(prev => prev.map(t => 
      t.id === id ? { ...t, rating, review, status: 'completed' as const } : t
    ));
  };

  const handleCompleteTrip = (id: string) => {
    setTickets(prev => prev.map(t => 
      t.id === id ? { ...t, status: 'completed' as const } : t
    ));
  };

  return (
    <div className="min-h-screen flex flex-col font-tajawal">
      <Navbar user={user} onLogout={handleLogout} onNavigate={setCurrentPage} currentPage={currentPage} />
      <main className="flex-grow bg-[#fafbfc]">
        {currentPage === 'login' && <AuthForm onLogin={handleLogin} />}
        {currentPage === 'my-tickets' && (
          user ? (
            <PastTrips 
              tickets={tickets} 
              onRate={handleRateTicket} 
              onMarkComplete={handleCompleteTrip}
            />
          ) : (
            <AuthForm onLogin={handleLogin} />
          )
        )}
        {currentPage === 'home' && (
          <div className="container mx-auto px-4 py-20 text-center space-y-8">
            <h1 className="text-6xl font-black text-blue-900 leading-tight">سافر كالملوك مع <span className="text-amber-500">تاج باص</span></h1>
            <p className="text-xl text-gray-500 max-w-2xl mx-auto">اختر حافلتك وسائقك حسب تقييمك الشخصي، لضمان أعلى مستويات الراحة والأمان في كل رحلة.</p>
            {user ? (
              <BookingFlow onComplete={addTicket} />
            ) : (
              <button 
                onClick={() => setCurrentPage('login')} 
                className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black text-xl hover:bg-blue-800 transition-all shadow-xl hover:shadow-blue-200"
              >
                ابدأ الحجز الآن
              </button>
            )}
          </div>
        )}
      </main>
      <footer className="bg-blue-950 text-blue-200 py-10 text-center border-t border-blue-900">
        <p>© 2024 تاج باص Taj Bus. جميع الحقوق محفوظة.</p>
      </footer>
    </div>
  );
};
export default App;

