import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import AuthForm from './components/AuthForm';
import BookingFlow from './components/BookingFlow';
import PastTrips from './components/PastTrips';
import ComplaintSystem from './components/ComplaintSystem';
import { User, Ticket } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);

  // تحميل البيانات من localStorage
  useEffect(() => {
    const savedUser = localStorage.getItem('taj_bus_user');
    if (savedUser) setUser(JSON.parse(savedUser));

    const savedTickets = localStorage.getItem('taj_bus_tickets');
    if (savedTickets) setTickets(JSON.parse(savedTickets));
  }, []);

  // حفظ التذاكر عند التغيير
  useEffect(() => {
    localStorage.setItem('taj_bus_tickets', JSON.stringify(tickets));
  }, [tickets]);

  const handleLogin = (u: User) => { 
    setUser(u); 
    localStorage.setItem('taj_bus_user', JSON.stringify(u));
    setCurrentPage('home'); 
  };

  const handleLogout = () => { 
    setUser(null); 
    localStorage.removeItem('taj_bus_user');
    setCurrentPage('home'); 
  };

  const addTicket = (t: Ticket) => { 
    setTickets([t, ...tickets]); 
    setCurrentPage('my-tickets'); 
  };

  const handleRateTicket = (id: string, rating: number, review: string) => {
    setTickets(prev => prev.map(t => 
      t.id === id ? { ...t, rating, review, status: 'completed' as const } : t
    ));
  };

  const handleCompleteTrip = (id: string) => {
    setTickets(prev => prev.map(t => 
      t.id === id ? { ...t, status: 'completed' as const } : t
    ));
  };

  return (
    <div className="min-h-screen flex flex-col font-tajawal bg-[#f8fafc]">
      <Navbar user={user} onLogout={handleLogout} onNavigate={setCurrentPage} currentPage={currentPage} />

      <main className="flex-grow">
        {currentPage === 'login' && <AuthForm onLogin={handleLogin} />}

        {currentPage === 'complaints' && (
          <div className="animate-fadeIn">
            <div className="bg-blue-900 text-white py-12 text-center">
              <h2 className="text-3xl font-black mb-2">مركز خدمة العملاء ذكي</h2>
              <p className="text-blue-200">نحن هنا للاستماع إليك ومساعدتك في أي وقت</p>
            </div>
            <ComplaintSystem />
          </div>
        )}

        {currentPage === 'my-tickets' && (
          user ? (
            <PastTrips 
              tickets={tickets} 
              onRate={handleRateTicket} 
              onMarkComplete={handleCompleteTrip}
            />
          ) : (
            <div className="flex flex-col items-center justify-center py-32 text-center space-y-6">
               <div className="bg-amber-100 p-8 rounded-full text-amber-600 animate-bounce">
                  <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"></path><polyline points="10 17 15 12 10 7"></polyline><line x1="15" y1="12" x2="3" y2="12"></line></svg>
               </div>
               <h2 className="text-2xl font-black text-blue-900">يجب تسجيل الدخول أولاً</h2>
               <p className="text-gray-500 max-w-sm">سجل دخولك الآن لتتمكن من استعراض تذاكرك السابقة وتقييم رحلاتك</p>
               <button onClick={() => setCurrentPage('login')} className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black shadow-lg">دخول الآن</button>
            </div>
          )
        )}

        {currentPage === 'home' && (
          <div className="space-y-12 pb-20">
            <div className="relative h-[400px] flex items-center justify-center overflow-hidden bg-blue-900">
              <div className="absolute inset-0 opacity-20">
                <div className="absolute inset-0 bg-gradient-to-b from-blue-900 via-transparent to-blue-900"></div>
                <img src="https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover" alt="bus" />
              </div>
              <div className="relative z-10 container mx-auto px-4 text-center">
                <h1 className="text-5xl md:text-7xl font-black text-white mb-6 leading-tight">
                  سافر كالملوك مع <span className="text-amber-500 underline decoration-amber-500/30">تاج باص</span>
                </h1>
                <p className="text-xl text-blue-100 max-w-2xl mx-auto mb-10">
                  أول منصة حجز تتيح لك اختيار سائقك المفضل ونوع الحافلة الملكية بلمسة واحدة.
                </p>
                {!user && (
                  <button 
                    onClick={() => setCurrentPage('login')} 
                    className="bg-amber-500 text-blue-900 px-12 py-5 rounded-2xl font-black text-xl hover:bg-amber-400 transition-all shadow-2xl hover:scale-105"
