            {!user && (
               <div className="container mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-8 py-10">
                  {[
                    { title: "أمان تام", desc: "سائقين محترفين ومعتمدين بتقييمات عالية من الركاب.", icon: "🛡️" },
                    { title: "راحة ملكية", desc: "أسطول من أحدث الحافلات المجهزة بكافة سبل الراحة.", icon: "👑" },
