                    </div>
                  ))}
               </div>
            )}
          </div>
        )}
      </main>

      <footer className="bg-blue-950 text-blue-300 py-12 border-t border-blue-900">
        <div className="container mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-10 text-center md:text-right">
          <div>
            <h4 className="text-white font-black text-xl mb-4 italic">تاج باص Taj Bus</h4>
            <p className="text-sm leading-relaxed">الخيار الأول للمسافر الباحث عن الفخامة والأمان في قلب مصر. نحن نعيد تعريف مفهوم النقل الجماعي.</p>
          </div>
          <div>
            <h4 className="text-white font-black text-lg mb-4">روابط سريعة</h4>
            <ul className="space-y-2 text-sm">
              <li><button onClick={() => setCurrentPage('home')} className="hover:text-amber-500">الرئيسية</button></li>
              <li><button onClick={() => setCurrentPage('complaints')} className="hover:text-amber-500">مركز المساعدة</button></li>
              <li><button className="hover:text-amber-500">شروط الاستخدام</button></li>
