import { User, Ticket, BookingState, BusType } from '../types';

// محاكاة قاعدة بيانات مركزية
const DB_KEYS = {
  USERS: 'taj_bus_db_users',
  TICKETS: 'taj_bus_db_tickets',
  SESSION: 'taj_bus_db_session'
};

const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const BackendAPI = {
  // --- نظام الحسابات (Auth) ---
  async signup(userData: any): Promise<{ success: boolean; user?: User; message?: string }> {
    await delay(1000);
    const users = JSON.parse(localStorage.getItem(DB_KEYS.USERS) || '[]');

    if (users.find((u: any) => u.email === userData.email)) {
      return { success: false, message: 'هذا البريد الإلكتروني مسجل بالفعل' };
    }

    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: userData.name,
      email: userData.email,
      loggedIn: true
    };

    users.push({ ...newUser, password: userData.password });
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    localStorage.setItem(DB_KEYS.SESSION, JSON.stringify(newUser));
    return { success: true, user: newUser };
  },

  async login(email: string, pass: string): Promise<{ success: boolean; user?: User; message?: string }> {
    await delay(1000);
    const users = JSON.parse(localStorage.getItem(DB_KEYS.USERS) || '[]');
    const user = users.find((u: any) => u.email === email && u.password === pass);

    if (user) {
      const sessionUser: User = { id: user.id, name: user.name, email: user.email, loggedIn: true };
      localStorage.setItem(DB_KEYS.SESSION, JSON.stringify(sessionUser));
      return { success: true, user: sessionUser };
    }
    return { success: false, message: 'بيانات الدخول غير صحيحة' };
  },

  async logout() {
    localStorage.removeItem(DB_KEYS.SESSION);
  },

  async getSession(): Promise<User | null> {
    const session = localStorage.getItem(DB_KEYS.SESSION);
    return session ? JSON.parse(session) : null;
  },

  // --- نظام الحجز (Booking & Database) ---
  async getOccupiedSeats(date: string, time: string, driverId: string): Promise<number[]> {
    const allTickets: Ticket[] = JSON.parse(localStorage.getItem(DB_KEYS.TICKETS) || '[]');
    return allTickets
      .filter(t => t.date === date && t.departureTime === time && t.driverId === driverId && t.status !== 'cancelled')
      .flatMap(t => t.selectedSeats);
  },

  async createBooking(bookingData: BookingState, userId: string): Promise<{ success: boolean; ticket?: Ticket }> {
    await delay(1500);

    // Server-side validation: التأكد أن المقاعد لم تحجز في هذه الأثناء
    const occupied = await this.getOccupiedSeats(bookingData.date, bookingData.departureTime, bookingData.driver?.id || '');
    const isTaken = bookingData.selectedSeats.some(s => occupied.includes(s));

    if (isTaken) {
      throw new Error('عذراً، بعض المقاعد التي اخترتها تم حجزها للتو من قبل مستخدم آخر');
    }

    const tickets = JSON.parse(localStorage.getItem(DB_KEYS.TICKETS) || '[]');
    const newTicket: Ticket = {
      id: 'TAJ-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
      userId,
      ...bookingData,
      driverId: bookingData.driver?.id || '',
      price: (bookingData.selectedSeats.length) * 150, // تبسيط للسعر
      status: 'upcoming',
      paymentStatus: 'paid',
      paymentId: 'PAY-' + Date.now()
    };

    tickets.push(newTicket);
    localStorage.setItem(DB_KEYS.TICKETS, JSON.stringify(tickets));
    return { success: true, ticket: newTicket };
  },

  async getUserTickets(userId: string): Promise<Ticket[]> {
    await delay(500);
    const allTickets: Ticket[] = JSON.parse(localStorage.getItem(DB_KEYS.TICKETS) || '[]');
    return allTickets.filter(t => t.userId === userId).reverse();
  }
};

