import React, { useState, useEffect } from 'react';
import { CITIES, BUS_PRICES, DRIVERS, TRIP_SCHEDULES } from '../constants';
import { BusType, BookingState, Ticket } from '../types';
import { BackendAPI } from '../services/api';
import PaymentForm from './PaymentForm';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
  userId: string;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete, userId }) => {
  const [step, setStep] = useState(1);
  const [occupiedSeats, setOccupiedSeats] = useState<number[]>([]);
  const [booking, setBooking] = useState<BookingState>({
    from: '', to: '', busType: BusType.STANDARD, driver: null, date: '', departureTime: '', arrivalTime: '', selectedSeats: []
  });

  // جلب المقاعد المحجوزة عند اختيار الموعد والسائق
  useEffect(() => {
    if (booking.date && booking.departureTime && booking.driver) {
      BackendAPI.getOccupiedSeats(booking.date, booking.departureTime, booking.driver.id)
        .then(seats => setOccupiedSeats(seats));
    }
  }, [booking.date, booking.departureTime, booking.driver]);

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const toggleSeat = (seat: number) => {
    if (occupiedSeats.includes(seat)) return; // منع اختيار مقعد محجوز
    setBooking(prev => ({
      ...prev,
      selectedSeats: prev.selectedSeats.includes(seat) ? prev.selectedSeats.filter(s => s !== s) : [...prev.selectedSeats, seat]
    }));
  };

  const handlePaymentSuccess = async () => {
    try {
      const result = await BackendAPI.createBooking(booking, userId);
      if (result.success && result.ticket) {
        onComplete(result.ticket);
      }
    } catch (err: any) {
      alert(err.message);
      setStep(5); // العودة لاختيار المقاعد إذا فشل الحجز بسبب تعارض
    }
  };

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-10 border border-gray-100">
        {/* Progress Bar */}
        <div className="flex justify-between mb-10">
          {[1, 2, 3, 4, 5, 6].map((s) => (
            <div key={s} className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-xs ${step >= s ? 'bg-blue-900 text-white' : 'bg-gray-100 text-gray-400'}`}>
              {s}
            </div>
          ))}
        </div>

        {step === 1 && (
          <div className="space-y-6 animate-fadeIn">
            <h3 className="text-2xl font-black text-blue-900">تحديد الوجهة</h3>
            <div className="grid grid-cols-2 gap-4">
              <select className="p-4 rounded-xl bg-gray-50 border outline-none" onChange={e => setBooking({...booking, from: e.target.value})}>
                <option value="">من</option>
                {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <select className="p-4 rounded-xl bg-gray-50 border outline-none" onChange={e => setBooking({...booking, to: e.target.value})}>
                <option value="">إلى</option>
                {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <input type="date" className="w-full p-4 rounded-xl bg-gray-50 border outline-none" onChange={e => setBooking({...booking, date: e.target.value})} />
            <button onClick={handleNext} disabled={!booking.from || !booking.to || !booking.date} className="w-full bg-blue-900 text-white py-4 rounded-xl font-black disabled:opacity-50">التالي</button>
          </div>
        )}

        {/* ... بقية الخطوات تم تحسينها لتتوافق مع الـ BackendAPI ... */}

        {step === 5 && (
          <div className="space-y-6 text-center animate-fadeIn">
             <h3 className="text-2xl font-black text-blue-900">خريطة المقاعد</h3>
             <p className="text-xs text-gray-400 mb-4">المقاعد باللون الأحمر محجوزة بالفعل من مستخدمين آخرين</p>
             <div className="bg-gray-100 p-8 rounded-3xl inline-block mx-auto mb-6">
               <div className="grid grid-cols-4 gap-3">
                 {Array.from({length: 20}, (_, i) => i + 1).map(s => {
                   const isOccupied = occupiedSeats.includes(s);
                   return (
                     <button 
                      key={s} 
                      disabled={isOccupied}
                      onClick={() => toggleSeat(s)} 
                      className={`w-12 h-12 rounded-xl border-2 font-black transition-all 
                        ${isOccupied ? 'bg-red-100 border-red-200 text-red-300 cursor-not-allowed' : 
                          booking.selectedSeats.includes(s) ? 'bg-amber-500 border-amber-600 text-white' : 'bg-white border-gray-100'}`}
                     >
                       {s}
                     </button>
                   );
                 })}
               </div>
             </div>
             <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-4 rounded-xl font-bold">رجوع</button>
              <button onClick={handleNext} disabled={booking.selectedSeats.length === 0} className="flex-[2] bg-blue-900 text-white py-4 rounded-xl font-black disabled:opacity-50">تأكيد الحجز</button>
            </div>
          </div>
        )}

        {step === 6 && (
          <PaymentForm 
            amount={booking.selectedSeats.length * 150} 
            onSuccess={handlePaymentSuccess} 
            onCancel={handleBack} 
          />
        )}

        {/* إضافة خطوات (2,3,4) بشكل مشابه للنسخة السابقة مع ربطها بالـ state الجديد */}
        {(step > 1 && step < 5) && (
           <div className="animate-fadeIn space-y-4">
              <h3 className="text-xl font-black text-blue-900">
                {step === 2 ? 'اختر الموعد' : step === 3 ? 'نوع الحافلة' : 'اختر السائق'}
