              <button onClick={handleNext} disabled={booking.selectedSeats.length === 0} className="flex-[2] bg-blue-900 text-white py-4 rounded-xl font-black disabled:opacity-50">تأكيد الحجز</button>
            </div>
          </div>
        )}

        {step === 6 && (
          <PaymentForm 
            amount={booking.selectedSeats.length * 150} 
            onSuccess={handlePaymentSuccess} 
            onCancel={handleBack} 
          />
        )}

        {/* إضافة خطوات (2,3,4) بشكل مشابه للنسخة السابقة مع ربطها بالـ state الجديد */}
        {(step > 1 && step < 5) && (
           <div className="animate-fadeIn space-y-4">
              <h3 className="text-xl font-black text-blue-900">
                {step === 2 ? 'اختر الموعد' : step === 3 ? 'نوع الحافلة' : 'اختر السائق'}
              </h3>
              <p className="text-gray-400 text-sm italic">اضغط "التالي" للمتابعة (في نسخة الـ Full Stack، هذه الاختيارات يتم التحقق منها برمجياً)</p>
              {step === 4 && (
                <div className="grid grid-cols-1 gap-2">
                   {DRIVERS.map(d => (
                     <div key={d.id} onClick={() => setBooking({...booking, driver: d})} className={`p-4 border rounded-xl cursor-pointer ${booking.driver?.id === d.id ? 'bg-amber-50 border-amber-500' : ''}`}>
                       {d.name}
                     </div>
                   ))}
                </div>
              )}
              {step === 2 && (
                <div className="grid grid-cols-1 gap-2">
                   {TRIP_SCHEDULES.map(ts => (
                     <div key={ts.id} onClick={() => setBooking({...booking, departureTime: ts.departureTime, arrivalTime: ts.arrivalTime})} className={`p-4 border rounded-xl cursor-pointer ${booking.departureTime === ts.departureTime ? 'bg-blue-50 border-blue-500' : ''}`}>
                       {ts.label} ({ts.departureTime})
                     </div>
                   ))}
                </div>
              )}
              <div className="flex gap-4 mt-6">
                <button onClick={handleBack} className="flex-1 bg-gray-100 py-4 rounded-xl font-bold">رجوع</button>
                <button onClick={handleNext} className="flex-[2] bg-blue-900 text-white py-4 rounded-xl font-black">التالي</button>
              </div>
           </div>
        )}
      </div>
    </div>
  );
};
export default BookingFlow;

