import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import AuthForm from './components/AuthForm';
import BookingFlow from './components/BookingFlow';
import PastTrips from './components/PastTrips';
import DatabaseExplorer from './components/DatabaseExplorer';
import { BackendAPI } from './services/api';
import { User, Ticket } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [user, setUser] = useState<User | null>(null);
  const [tickets, setTickets] = useState<Ticket[]>([]);
  const [loading, setLoading] = useState(true);
  const [isExplorerOpen, setIsExplorerOpen] = useState(false);

  // Load Session and Tickets on start (Real DB Call)
  useEffect(() => {
    const initApp = async () => {
      try {
        const sessionUser = await BackendAPI.getSession();
        if (sessionUser) {
          setUser(sessionUser);
          const userTickets = await BackendAPI.getUserTickets(sessionUser.id);
          setTickets(userTickets);
        }
      } catch (err) {
        console.error("Database Init Error", err);
      } finally {
        setLoading(false);
      }
    };
    initApp();
  }, []);

  const handleLogin = async (u: User) => { 
    setUser(u); 
    const userTickets = await BackendAPI.getUserTickets(u.id);
    setTickets(userTickets);
    setCurrentPage('home'); 
  };

  const handleLogout = async () => { 
    await BackendAPI.logout();
    setUser(null); 
    setTickets([]);
    setCurrentPage('home'); 
  };

  const handleBookingComplete = async (ticket: Ticket) => { 
    const updatedTickets = await BackendAPI.getUserTickets(user!.id);
    setTickets(updatedTickets);
    setCurrentPage('my-tickets'); 
  };

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-blue-900">
      <div className="flex flex-col items-center gap-4">
        <div className="w-16 h-16 border-4 border-amber-500 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-white font-bold animate-pulse">جاري تشغيل محرك قاعدة البيانات...</p>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col font-tajawal bg-[#f8fafc]">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={setCurrentPage} 
        onOpenExplorer={() => setIsExplorerOpen(true)}
        currentPage={currentPage} 
      />

      <main className="flex-grow">
        {currentPage === 'login' && <AuthForm onLogin={handleLogin} />}

        {currentPage === 'my-tickets' && (
          user ? (
            <PastTrips 
              tickets={tickets} 
              onRate={() => {}} 
              onMarkComplete={() => {}}
            />
          ) : (
            <div className="flex flex-col items-center justify-center py-32 text-center space-y-6">
               <div className="bg-amber-100 p-8 rounded-full text-amber-600">
                  <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4"></path><polyline points="10 17 15 12 10 7"></polyline><line x1="15" y1="12" x2="3" y2="12"></line></svg>
               </div>
               <h2 className="text-2xl font-black text-blue-900">يجب تسجيل الدخول أولاً</h2>
               <button onClick={() => setCurrentPage('login')} className="bg-blue-900 text-white px-10 py-4 rounded-2xl font-black shadow-lg">دخول الآن</button>
            </div>
          )
        )}

        {currentPage === 'home' && (
          <div className="space-y-12 pb-20">
            <div className="relative h-[400px] flex items-center justify-center overflow-hidden bg-blue-900">
              <div className="absolute inset-0 opacity-20">
                <img src="https://images.unsplash.com/photo-1544620347-c4fd4a3d5957?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover" alt="bus" />
              </div>
              <div className="relative z-10 text-center">
                <h1 className="text-5xl md:text-7xl font-black text-white mb-6">سافر كالملوك</h1>
                {!user && (
                  <button onClick={() => setCurrentPage('login')} className="bg-amber-500 text-blue-900 px-12 py-5 rounded-2xl font-black text-xl hover:scale-105 transition-transform shadow-2xl">
                    سجل حسابك في قاعدة البيانات
                  </button>
                )}
              </div>
            </div>

            {user && (
              <div className="container mx-auto px-4 -mt-20 relative z-20">
                <BookingFlow onComplete={handleBookingComplete} userId={user.id} />
              </div>
            )}
          </div>
        )}
      </main>

      <DatabaseExplorer isOpen={isExplorerOpen} onClose={() => setIsExplorerOpen(false)} />

      {/* زر عائم احتياطي */}
      {!isExplorerOpen && (
        <button 
          onClick={() => setIsExplorerOpen(true)}
          className="fixed bottom-4 left-4 bg-gray-800 text-white p-4 rounded-2xl shadow-2xl hover:scale-110 transition-all z-[100] flex items-center gap-2 text-xs font-bold border border-gray-700"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><ellipse cx="12" cy="5" rx="9" ry="3"></ellipse><path d="M21 12c0 1.66-4 3-9 3s-9-1.34-9-3"></path><path d="M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5"></path></svg>
          فتح قاعدة البيانات
        </button>
      )}

      <footer className="bg-blue-950 text-blue-400 py-6 text-center text-xs border-t border-blue-900">
        © 2024 تاج باص - نظام مدعوم بمحرك IndexedDB Real-time Database
      </footer>
    </div>
  );
};
export default App;

