import React, { useState, useEffect } from 'react';
import { CITIES, BUS_PRICES, DRIVERS, TRIP_SCHEDULES } from '../constants';
import { BusType, BookingState, Ticket } from '../types';
import { BackendAPI } from '../services/api';
import PaymentForm from './PaymentForm';

interface BookingFlowProps {
  onComplete: (ticket: Ticket) => void;
  userId: string;
}

const BookingFlow: React.FC<BookingFlowProps> = ({ onComplete, userId }) => {
  const [step, setStep] = useState(1);
  const [occupiedSeats, setOccupiedSeats] = useState<number[]>([]);
  const [booking, setBooking] = useState<BookingState>({
    from: '', to: '', busType: BusType.STANDARD, driver: null, date: '', departureTime: '', arrivalTime: '', selectedSeats: []
  });

  useEffect(() => {
    if (booking.date && booking.departureTime && booking.driver) {
      BackendAPI.getOccupiedSeats(booking.date, booking.departureTime, booking.driver.id)
        .then(seats => setOccupiedSeats(seats));
    }
  }, [booking.date, booking.departureTime, booking.driver]);

  const handleNext = () => setStep(step + 1);
  const handleBack = () => setStep(step - 1);

  const toggleSeat = (seat: number) => {
    if (occupiedSeats.includes(seat)) return;
    setBooking(prev => ({
      ...prev,
      selectedSeats: prev.selectedSeats.includes(seat) ? prev.selectedSeats.filter(s => s !== seat) : [...prev.selectedSeats, seat]
    }));
  };

  const handlePaymentSuccess = async () => {
    try {
      const result = await BackendAPI.createBooking(booking, userId);
      if (result.success && result.ticket) {
        onComplete(result.ticket);
      }
    } catch (err: any) {
      alert(err.message);
      setStep(5);
    }
  };

  const canGoNext = () => {
    switch(step) {
      case 1: return booking.from && booking.to && booking.from !== booking.to && booking.date;
      case 2: return booking.departureTime !== '';
      case 3: return true; // نوع الحافلة له قيمة افتراضية
      case 4: return booking.driver !== null;
      case 5: return booking.selectedSeats.length > 0;
      default: return true;
    }
  };

  return (
    <div className="max-w-4xl mx-auto my-8 p-4">
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-6 md:p-10 border border-gray-100">
        {/* Progress Stepper */}
        <div className="flex justify-between items-center mb-12 relative px-4">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 z-0"></div>
          <div className="absolute top-1/2 left-0 h-1 bg-blue-900 -translate-y-1/2 z-0 transition-all duration-500" style={{ width: `${((step - 1) / 5) * 100}%` }}></div>
          {[1, 2, 3, 4, 5, 6].map((s) => (
            <div key={s} className={`relative z-10 w-10 h-10 rounded-full flex items-center justify-center font-black text-sm transition-all duration-300 ${step >= s ? 'bg-blue-900 text-white scale-110 shadow-lg shadow-blue-900/20' : 'bg-white border-2 border-gray-100 text-gray-300'}`}>
              {s}
            </div>
          ))}
        </div>

        {/* Step 1: Destination & Date */}
        {step === 1 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="text-center">
              <h3 className="text-3xl font-black text-blue-900">أين وجهتك القادمة؟</h3>
              <p className="text-gray-400 mt-2 font-medium">اختر المدن وتاريخ السفر لبدء الحجز</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-400 mr-2">من محافظة</label>
                <select className="w-full p-5 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-amber-500 outline-none transition-all appearance-none cursor-pointer" value={booking.from} onChange={e => setBooking({...booking, from: e.target.value})}>
                  <option value="">اختر نقطة الانطلاق</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-400 mr-2">إلى محافظة</label>
                <select className="w-full p-5 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-amber-500 outline-none transition-all appearance-none cursor-pointer" value={booking.to} onChange={e => setBooking({...booking, to: e.target.value})}>
                  <option value="">اختر وجهة الوصول</option>
                  {CITIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 mr-2">تاريخ السفر</label>
              <input type="date" className="w-full p-5 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-amber-500 outline-none transition-all cursor-pointer" value={booking.date} onChange={e => setBooking({...booking, date: e.target.value})} min={new Date().toISOString().split('T')[0]} />
            </div>
            <button onClick={handleNext} disabled={!canGoNext()} className="w-full bg-blue-900 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-blue-900/20 disabled:opacity-30 disabled:grayscale transition-all">ابحث عن الرحلات المتاحة</button>
          </div>
        )}

        {/* Step 2: Departure Time */}
        {step === 2 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="text-center">
              <h3 className="text-3xl font-black text-blue-900">اختر موعد الرحلة</h3>
              <p className="text-gray-400 mt-2 font-medium">مواعيد دقيقة لضمان راحتك</p>
            </div>
            <div className="grid grid-cols-1 gap-4">
               {TRIP_SCHEDULES.map(ts => (
                 <div 
                  key={ts.id} 
                  onClick={() => setBooking({...booking, departureTime: ts.departureTime, arrivalTime: ts.arrivalTime})} 
                  className={`p-6 border-2 rounded-[2rem] cursor-pointer transition-all flex justify-between items-center group ${booking.departureTime === ts.departureTime ? 'bg-blue-50 border-blue-600 shadow-lg' : 'bg-white border-gray-100 hover:border-blue-200'}`}
                 >
                   <div className="flex items-center gap-6">
                      <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl transition-all ${booking.departureTime === ts.departureTime ? 'bg-blue-900 text-white' : 'bg-gray-100 text-gray-400'}`}>
                        {ts.departureTime.split(':')[0] >= '18' ? '🌙' : '☀️'}
                      </div>
                      <div>
                        <p className="text-lg font-black text-blue-900">{ts.label}</p>
                        <p className="text-xs text-gray-400 font-bold">وصول متوقع في تمام {ts.arrivalTime}</p>
                      </div>
                   </div>
                   <div className="text-2xl font-black text-blue-900">{ts.departureTime}</div>
                 </div>
               ))}
            </div>
            <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-5 rounded-2xl font-black text-gray-500">رجوع</button>
              <button onClick={handleNext} disabled={!canGoNext()} className="flex-[2] bg-blue-900 text-white py-5 rounded-2xl font-black shadow-xl disabled:opacity-30 transition-all">التالي</button>
            </div>
          </div>
        )}

        {/* Step 3: Bus Type (The fix you requested) */}
        {step === 3 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="text-center">
              <h3 className="text-3xl font-black text-blue-900">اختر نوع الحافلة</h3>
              <p className="text-gray-400 mt-2 font-medium">مستويات مختلفة من الرفاهية تناسب احتياجاتك</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               {(Object.values(BusType) as BusType[]).map(type => (
                 <div 
                  key={type} 
                  onClick={() => setBooking({...booking, busType: type})} 
                  className={`p-8 border-2 rounded-[2.5rem] cursor-pointer transition-all text-center relative overflow-hidden group ${booking.busType === type ? 'bg-amber-50 border-amber-500 shadow-xl scale-105' : 'bg-white border-gray-100 hover:border-amber-200'}`}
                 >
                   <div className={`text-4xl mb-4 transition-transform group-hover:scale-125 ${booking.busType === type ? 'animate-bounce' : ''}`}>
                      {type === BusType.STANDARD ? '🚌' : type === BusType.VIP ? '🛋️' : '👑'}
                   </div>
                   <h4 className="text-xl font-black text-blue-900 mb-2">{type}</h4>
                   <p className="text-[10px] text-gray-400 font-bold mb-4">
                     {type === BusType.STANDARD ? 'تكييف، واي فاي، مقاعد مريحة' : type === BusType.VIP ? 'شاشات عرض، مقعد واسع، وجبة' : 'خدمة ملكية، مساج، شاشة 4K'}
                   </p>
                   <div className="text-2xl font-black text-amber-600">
                     {BUS_PRICES[type]} <span className="text-xs">ج.م</span>
                   </div>
                   {booking.busType === type && (
                     <div className="absolute top-4 left-4 text-amber-500">
                       <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 15l-5-5 1.41-1.41L10 14.17l7.59-7.59L19 8l-9 9z"/></svg>
                     </div>
                   )}
                 </div>
               ))}
            </div>
            <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-5 rounded-2xl font-black text-gray-500">رجوع</button>
              <button onClick={handleNext} className="flex-[2] bg-blue-900 text-white py-5 rounded-2xl font-black shadow-xl transition-all">التالي</button>
            </div>
          </div>
        )}

        {/* Step 4: Driver Selection */}
        {step === 4 && (
          <div className="space-y-8 animate-fadeIn">
            <div className="text-center">
              <h3 className="text-3xl font-black text-blue-900">من سيقود بك؟</h3>
              <p className="text-gray-400 mt-2 font-medium">سائقونا هم نخبة من المحترفين بأعلى التقييمات</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {DRIVERS.map(d => (
                 <div 
                  key={d.id} 
                  onClick={() => setBooking({...booking, driver: d})} 
                  className={`p-6 border-2 rounded-[2rem] cursor-pointer transition-all flex items-center gap-6 ${booking.driver?.id === d.id ? 'bg-blue-50 border-blue-600 shadow-lg' : 'bg-white border-gray-100 hover:border-blue-100'}`}
                 >
                   <div className="relative">
                     <img src={d.photo} className="w-16 h-16 rounded-2xl object-cover shadow-md" alt={d.name} />
                     <div className="absolute -bottom-2 -right-2 bg-amber-500 text-white text-[10px] font-black px-2 py-1 rounded-lg">⭐ {d.rating}</div>
                   </div>
                   <div>
                     <p className="font-black text-blue-900">{d.name}</p>
                     <p className="text-xs text-gray-400 font-bold">{d.experience}</p>
                   </div>
                   {booking.driver?.id === d.id && (
                     <div className="mr-auto text-blue-600">
                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
                     </div>
                   )}
                 </div>
               ))}
            </div>
            <div className="flex gap-4">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-5 rounded-2xl font-black text-gray-500">رجوع</button>
              <button onClick={handleNext} disabled={!canGoNext()} className="flex-[2] bg-blue-900 text-white py-5 rounded-2xl font-black shadow-xl disabled:opacity-30 transition-all">التالي</button>
            </div>
          </div>
        )}

        {/* Step 5: Seat Selection */}
        {step === 5 && (
          <div className="space-y-8 text-center animate-fadeIn">
             <div className="text-center">
              <h3 className="text-3xl font-black text-blue-900">اختر مقعدك المفضل</h3>
              <p className="text-gray-400 mt-2 font-medium">المقاعد الملونة بالأحمر محجوزة مسبقاً</p>
             </div>
             <div className="bg-gray-50 p-8 md:p-12 rounded-[3rem] inline-block mx-auto border border-gray-100 relative">
               <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-gray-200 px-8 py-1 rounded-full text-[10px] font-black text-gray-400 uppercase tracking-widest">المقدمة</div>
               <div className="grid grid-cols-4 gap-4 mt-6">
                 {Array.from({length: 20}, (_, i) => i + 1).map(s => {
                   const isOccupied = occupiedSeats.includes(s);
                   const isSelected = booking.selectedSeats.includes(s);
                   return (
                     <button 
                      key={s} 
                      disabled={isOccupied}
                      onClick={() => toggleSeat(s)} 
                      className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl border-2 font-black transition-all flex items-center justify-center
                        ${isOccupied ? 'bg-red-50 border-red-100 text-red-200 cursor-not-allowed' : 
                          isSelected ? 'bg-blue-900 border-blue-900 text-white shadow-xl scale-110' : 'bg-white border-gray-200 text-gray-400 hover:border-blue-400 hover:text-blue-600'}`}
                     >
                       {s}
                     </button>
                   );
                 })}
               </div>
             </div>

             <div className="flex justify-center gap-6 text-xs font-bold">
               <div className="flex items-center gap-2"><div className="w-3 h-3 bg-white border border-gray-200 rounded-sm"></div> متاح</div>
               <div className="flex items-center gap-2"><div className="w-3 h-3 bg-blue-900 rounded-sm"></div> مختار</div>
               <div className="flex items-center gap-2"><div className="w-3 h-3 bg-red-100 border border-red-100 rounded-sm"></div> محجوز</div>
             </div>

             <div className="flex gap-4 mt-8">
              <button onClick={handleBack} className="flex-1 bg-gray-100 py-5 rounded-2xl font-black text-gray-500">رجوع</button>
              <button onClick={handleNext} disabled={!canGoNext()} className="flex-[2] bg-blue-900 text-white py-5 rounded-2xl font-black shadow-xl disabled:opacity-30 transition-all">تأكيد واختيار الدفع</button>
            </div>
          </div>
        )}

        {/* Step 6: Payment */}
        {step === 6 && (
          <PaymentForm 
            amount={booking.selectedSeats.length * BUS_PRICES[booking.busType]} 
            onSuccess={handlePaymentSuccess} 
            onCancel={handleBack} 
          />
        )}
      </div>
    </div>
  );
};
export default BookingFlow;
